import React from "react";
import styled from "@emotion/styled";
import { graphql } from "gatsby";
import Toc from "./Toc";
import { useEffect } from "react";

const Container = styled.div`
  width: 100%;
  background-color: #000;
  color: #fff;
  overflow-x: hidden;
`;

const MarkdownRenderer = styled.div`
  // Renderer Style
  display: flex;
  flex-direction: column;
  width: 768px;
  margin: 0 auto;
  word-break: break-all;

  // Markdown Style
  line-height: 1.8;
  font-size: 16px;
  font-weight: 400;

  // Apply Padding Attribute to All Elements
  p {
    padding: 3px 0;
  }

  // Adjust Heading Element Style
  h1,
  h2,
  h3 {
    font-weight: 800;
    margin-bottom: 30px;
  }

  * + h1,
  * + h2,
  * + h3 {
    margin-top: 50px;
  }

  hr + h1,
  hr + h2,
  hr + h3 {
    margin-top: 0;
  }

  h1 {
    font-size: 30px;
  }

  h2 {
    font-size: 25px;
  }

  h3 {
    font-size: 20px;
  }

  // Adjust Quotation Element Style
  blockquote {
    margin: 30px 0;
    padding: 5px 15px;
    border-left: 2px solid #fff;
    font-weight: 800;
  }

  // Adjust List Element Style
  ol,
  ul {
    margin-left: 20px;
    padding: 30px 0;
  }

  // Adjust Horizontal Rule style
  hr {
    border: 1px solid #fff;
    margin: 100px 0;
  }

  // Adjust Link Element Style
  a {
    color: #4263eb;
    text-decoration: underline;
  }

  .gatsby-highlight {
    position: relative;

    &:before {
      content: "";
      position: absolute;
      width: 100%;
      line-height: 20px;
      height: 40px;
      border-radius: 5px 5px 0 0;
      background-color: #fffefe42;
    }

    &:after {
      content: attr(data-language);
      position: absolute;
      right: 10px;
      top: 0;
    }
  }

  .gatsby-highlight-code-line {
    width: 100%;
    display: block;
    background-color: #53464e;
    /*     border-radius: 5px; */
    /*     padding: 4px; */
    position: relative;
  }

  // Adjust Code Style
  pre[class*="language-"] {
    margin: 30px 0;
    padding: 15px;
    font-size: 15px;
    position: relative;

    ::-webkit-scrollbar-thumb {
      background: rgba(255, 255, 255, 0.5);
      border-radius: 3px;
    }
  }

  code[class*="language-"],
  pre[class*="language-"] {
    tab-size: 2;
  }

  .language-text {
    padding: 2px 5px;
    margin: 0 3px;

    color: tomato;
  }

  img {
    max-width: 768px;
    margin: 0 auto;
    border-radius: 10px;
  }

  .anchor-header {
    background-image: url(https://www.iconsdb.com/icons/preview/white/link-xxl.png);
    background-position: center center;
    background-repeat: no-repeat;
    color: #fff;
  }

  // Markdown Responsive Design
  @media (max-width: 768px) {
    width: 100%;
    padding: 20px 20px;
    line-height: 1.6;
    font-size: 14px;

    h1 {
      font-size: 23px;
    }

    h2 {
      font-size: 20px;
    }

    h3 {
      font-size: 17px;
    }

    img {
      width: 100%;
    }

    hr {
      margin: 50px 0;
    }
  }
`;

const PostContent = function ({ html }) {
  return (
    <Container className="container">
      <MarkdownRenderer dangerouslySetInnerHTML={{ __html: html }} />
    </Container>
  );
};

export default PostContent;
