import React from "react";
import { graphql } from "gatsby";
import Template from "../components/Common/Template";
import PostHead from "../components/Post/PostHead";
import PostContent from "../components/Post/PostContent";
import CommentWidget from "../components/Post/CommentWidget";

const PostTemplate = function ({
  data: {
    allMarkdownRemark: { edges },
  },
  location: { href },
}) {
  const {
    node: {
      html,
      frontmatter: {
        title,
        summary,
        date,
        modifiedDate,
        category,
        tags,
        thumbnail: {
          childImageSharp: { gatsbyImageData },
          publicURL,
        },
      },
    },
  } = edges[0];

  return (
    <Template title={title} description={summary} url={href} image={publicURL} category={category}>
      <PostHead title={title} date={date} tags={tags} thumbnail={gatsbyImageData} category={category} modifiedDate={modifiedDate} />
      <PostContent html={html} />
      <CommentWidget />
    </Template>
  );
};

export default PostTemplate;

export const queryMarkdownDataBySlug = graphql`
  query queryMarkdownDataBySlug($slug: String) {
    allMarkdownRemark(filter: { fields: { slug: { eq: $slug } } }) {
      edges {
        node {
          html
          frontmatter {
            title
            summary
            date(formatString: "YYYY.MM.DD.")
            modifiedDate(formatString: "YYYY.MM.DD.")
            category
            tags
            thumbnail {
              childImageSharp {
                gatsbyImageData
              }
              publicURL
            }
          }
        }
      }
    }
  }
`;
