import React from "react";
import styled from "@emotion/styled";
import { GatsbyImage, IGatsbyImageData } from "gatsby-plugin-image";
import PostHeadInfo from "./PostHeadInfo";

const PostHeadWrapper = styled.div`
  position: relative;
  width: 100%;

  margin-top: 100px;

  @media (max-width: 768px) {
  }
`;

const BackgroundImage = styled((props) => <GatsbyImage {...props} style={{ position: "absolute" }} />)`
  z-index: -1;
  width: 100%;
  object-fit: cover;
  filter: brightness(0.25);

  @media (max-width: 768px) {
    height: 300px;
  }
`;

const PostHead = function ({ title, date, tags, thumbnail, category, modifiedDate }) {
  return (
    <PostHeadWrapper>
      <BackgroundImage image={thumbnail} alt="thumbnail" />
      <PostHeadInfo title={title} date={date} tags={tags} category={category} modifiedDate={modifiedDate} />
    </PostHeadWrapper>
  );
};

export default PostHead;
